using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    #region CreateOrder – Success

    [TestMethod]
    public void CreateOrder_WithSingleItem_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 3));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(30.00m, order.Total);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.IsNotNull(order.Id);
        Assert.ContainsSingle(order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_ReturnsSumOfLineItems()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 2), ("Gadget", 25.00m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(45.00m, order.Total);
        Assert.HasCount(2, order.Items);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        // Arrange
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 5.00m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_GeneratesUniqueIds()
    {
        // Arrange
        var items = CreateItems(("Widget", 5.00m, 1));

        // Act
        var order1 = _service.CreateOrder("cust-1", items);
        var order2 = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    #endregion

    #region CreateOrder – Validation

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 5.00m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));

        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    #endregion

    #region CreateOrder – Total calculation (data-driven)

    [TestMethod]
    [DynamicData(nameof(TotalCalculationData))]
    public void CreateOrder_VariousItems_CalculatesCorrectTotal(
        string description, List<OrderItem> items, decimal expectedTotal)
    {
        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(expectedTotal, order.Total);
    }

    public static IEnumerable<(string description, List<OrderItem> items, decimal expectedTotal)> TotalCalculationData =>
    [
        ("Single item, qty 1", CreateItems(("A", 9.99m, 1)), 9.99m),
        ("Single item, qty 5", CreateItems(("A", 2.50m, 5)), 12.50m),
        ("Two items", CreateItems(("A", 10m, 2), ("B", 5m, 3)), 35m),
        ("Zero price item", CreateItems(("Free", 0m, 10)), 0m),
    ];

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        // Arrange
        var items = CreateItems(("Widget", 5.00m, 1));
        var created = _service.CreateOrder("cust-1", items);

        // Act
        var retrieved = _service.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAllForCustomer()
    {
        // Arrange
        var items = CreateItems(("Widget", 5.00m, 1));
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-2", items);

        // Act
        var orders = _service.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var orders = _service.GetOrdersByCustomer("cust-999");

        Assert.IsEmpty(orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_DoesNotReturnOtherCustomersOrders()
    {
        // Arrange
        var items = CreateItems(("Widget", 5.00m, 1));
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-2", items);

        // Act
        var orders = _service.GetOrdersByCustomer("cust-1");

        // Assert
        var single = Assert.ContainsSingle(orders);
        Assert.AreEqual("cust-1", single.CustomerId);
    }

    #endregion
}

